// modules/tasks/module.contract.ts
import { defineContract } from 'aether';

export default defineContract({
  name: 'tasks',
  description: 'Handles task creation, retrieval, and status updates.',

  dependencies: { modules: ['auth'] },

  exposes: {
    routes: [
      { method: 'POST', path: '/tasks', auth: true },
      { method: 'GET', path: '/tasks/:id', auth: true },
      { method: 'PUT', path: '/tasks/:id/status', auth: true },
    ],
    functions: ['createTask', 'getTaskById', 'updateTaskStatus'],
    types: ['Task', 'TaskStatus', 'TaskError'],
  },

  sideEffects: [
    'writes to: tasks table',
    'reads from: users table',
  ],

  invariants: [
    'A task must always belong to exactly one user',
    'Deleted tasks must never be hard-deleted',
    'Illegal status transitions are not allowed',
  ],
});

// modules/tasks/lib/types.ts
import { z } from 'zod';

export const TaskStatus = z.enum(['todo', 'in_progress', 'done']);
export type TaskStatus = z.infer<typeof TaskStatus>;

export const TaskError = z.object({
  code: z.string(),
  message: z.string(),
});
export type TaskError = z.infer<typeof TaskError>;

// modules/tasks/lib/db.ts
import { query } from '../lib/db';

export async function createTask(userId: number, title: string, description: string): Promise<Task> {
  const result = await query('INSERT INTO tasks (user_id, title, description) VALUES ($1, $2, $3) RETURNING *', [userId, title, description]);
  return result.rows[0];
}

export async function getTaskById(taskId: number): Promise<Task | null> {
  const result = await query('SELECT * FROM tasks WHERE id = $1', [taskId]);
  return result.rows.length > 0 ? result.rows[0] : null;
}

export async function updateTaskStatus(taskId: number, status: TaskStatus): Promise<Task> {
  if (!['todo', 'in_progress', 'done'].includes(status)) {
    throw new Error('Invalid task status');
  }
  const result = await query('UPDATE tasks SET status = $1 WHERE id = $2 RETURNING *', [status, taskId]);
  return result.rows[0];
}

// modules/tasks/lib/validate.ts
import { z } from 'zod';

export function parseTaskCreateRequest(req: Request): Task {
  const schema = z.object({
    title: z.string().min(1),
    description: z.string(),
  });
  return schema.parse(req.body);
}

// modules/tasks/lib/auth.ts
import { requireUser } from '../lib/auth';

export async function createTaskHandler(req: Request, res: Response) {
  const user = await requireUser(req);
  const taskData = parseTaskCreateRequest(req);
  try {
    const task = await createTask(user.id, taskData.title, taskData.description);
    res.status(201).json(task);
  } catch (error) {
    res.status(400).json({ error: { code: 'task_creation_error', message: error.message } });
  }
}

export async function getTaskByIdHandler(req: Request, res: Response) {
  const taskId = parseInt(req.params.id, 10);
  try {
    const task = await getTaskById(taskId);
    if (task) {
      res.status(200).json(task);
    } else {
      res.status(404).json({ error: { code: 'task_not_found', message: 'Task not found' } });
    }
  } catch (error) {
    res.status(500).json({ error: { code: 'database_error', message: error.message } });
  }
}

export async function updateTaskStatusHandler(req: Request, res: Response) {
  const taskId = parseInt(req.params.id, 10);
  const status = req.body.status as TaskStatus;
  try {
    await requireUser(req);
    if (!['todo', 'in_progress', 'done'].includes(status)) {
      return res.status(400).json({ error: { code: 'invalid_status', message: 'Invalid task status' } });
    }
    const updatedTask = await updateTaskStatus(taskId, status);
    res.status(200).json(updatedTask);
  } catch (error) {
    if (error instanceof Error) {
      res.status(500).json({ error: { code: 'database_error', message: error.message } });
    } else {
      res.status(400).json({ error: { code: 'invalid_request', message: 'Invalid request' } });
    }
  }
}

// modules/tasks/routes.ts
import { Router } from 'bun';
import { createTaskHandler, getTaskByIdHandler, updateTaskStatusHandler } from '../lib/handlers';

const router = new Router();

router.post('/tasks', createTaskHandler);
router.get('/tasks/:id', getTaskByIdHandler);
router.put('/tasks/:id/status', updateTaskStatusHandler);

export default router;

