    if (error instanceof Error) {
      return new Response(JSON.stringify({ error: { code: 'task_creation_error', message: error.message } }), { status: 400 });
    }
    return new Response(JSON.stringify({ error: { code: 'database_error', message: error.message } }), { status: 500 });
