  const taskId = parseInt(req.params.id, 10);
  const status = req.body.status as TaskStatus;
  try {
    await requireUser(req);
    if (!['todo', 'in_progress', 'done'].includes(status)) {
      return new Response(JSON.stringify({ error: { code: 'invalid_status', message: 'Invalid task status' } }), { status: 400 });
    }
    const updatedTask = await updateTaskStatus(taskId, status);
    return new Response(JSON.stringify(updatedTask), { status: 200 });
  } catch (error) {
    if (error instanceof Error) {
      return new Response(JSON.stringify({ error: { code: 'database_error', message: error.message } }), { status: 500 });
    }
    return new Response(JSON.stringify({ error: { code: 'invalid_request', message: 'Invalid request' } }), { status: 400 });
  }
}

